---战斗显示对象管理
---@class LBattleViewUnitMgr
local LBattleViewUnitMgr = classX("LBattleViewUnitMgr",nil)

local LBattleViewUnit = require("LApp.gameplay.videobattle.view.obj.LBattleViewUnit")

local typeofCTextMesh = typeof(ProjectX.CTextMesh)

function LBattleViewUnitMgr:ctor()
    ---@type LBattleViewMgr
    self._viewMgr = nil

    ---当前对象列表{key=LBattleViewUnit,key=LBattleViewUnit,...}
    ---@type table<string,LBattleViewUnit>
    self._unitMap = {}

    ---A队
    ---@type LBattleViewUnit[]
    self._teamA = {}

    ---B队
    ---@type LBattleViewUnit[]
    self._teamB = {}
end

-----------------------------------------------------------------
function LBattleViewUnitMgr:Initialize()

end

function LBattleViewUnitMgr:SetupAll()
    for i, unit in pairs(self._unitMap) do
        unit:Setup()
    end
end

---@param viewMgr LBattleViewMgr
function LBattleViewUnitMgr:SetViewMgr(viewMgr)
    self._viewMgr = viewMgr
    self._effectMgr = viewMgr:GetEffectMgr()
    self._viewFace = viewMgr:GetViewFace()
end

function LBattleViewUnitMgr:SetRootNode(node)
    self._formationRoot = node
    self:LoadFormation()
end

function LBattleViewUnitMgr:SetBattleConfig(config)
    self._battleConfig = config
end

function LBattleViewUnitMgr:ClearCallback()
    self._localCallback = nil
end

function LBattleViewUnitMgr:ResumeBattle()
    for k,v in pairs(self._unitMap) do
        if not v:IsDead() then
            v:ReleaseHideKey("dead")
            v:ShowDisplayObject(true)

            v:SetHeroBgVisiable(true)
        end
        v:RefreshAllBuffEffect()
        v:UpdateCanReliveEff()
        v:SetPosByGrid()
    end
end

---@param logicMgr LBattleLogicMgr
---@param callback any
function LBattleViewUnitMgr:SetBattle(logicMgr, callback)
    self._logicMgr = logicMgr
    self._localCallback = callback
    ---@type LFightReportData
    self._reportData = logicMgr:GetReportData()
    self._battleFormation1 = self._reportData.formationA
    self._battleFormation2 = self._reportData.formationB
    self._isBattleMode = true

    self:LoadFormation()
end

---@param formation1 LxFormationObj
---@param formation2 LxFormationObj
function LBattleViewUnitMgr:SetFormation(formation1, formation2, callback)
    self._formationObj1 = formation1
    self._formationObj2 = formation2
    self._localCallback = callback
    self._isBattleMode = false
    self:LoadFormation()
end

function LBattleViewUnitMgr:GetUnitMap()
    return self._unitMap
end

function LBattleViewUnitMgr:SetEmpty()
    if IsNull(self._formationRoot) then
        return
    end
    local trans = self._formationRoot.transform
    local teamRoot1 = trans:Find("Formation1")
    local teamRoot2 = trans:Find("Formation2")
    for i = 1, BattlePosCount do
        local node1 = teamRoot1:Find(tostring(i))
        local stand1 = node1:Find("Stand")
        local node2 = teamRoot2:Find(tostring(i))
        local stand2 = node2:Find("Stand")
        if IsValid(stand1) then
            ShowAllChild(stand1.gameObject, false)
        end
        if IsValid(stand2) then
            ShowAllChild(stand2.gameObject, false)
        end
    end
end

function LBattleViewUnitMgr:GetPosNode(teamIdx, nodeIdx)
    local trans = self._formationRoot.transform
    local teamRoot = nil
    if teamIdx == BattleTeamSide.teamA then
        teamRoot = trans:Find("Formation1")
    else
        teamRoot = trans:Find("Formation2")
    end
    local node = teamRoot:Find(tostring(nodeIdx))
    return node
end

function LBattleViewUnitMgr:LoadFormation()
    if IsNull(self._formationRoot) then return end
    self._localIdx = 0
    self._localCnt = 0

    local formationData1 = self._viewFace:GetFormationData(1)
    local formationData2 = self._viewFace:GetFormationData(2)
    local trans = self._formationRoot.transform
    local teamRoot1 = trans:Find("Formation1")
    local teamRoot2 = trans:Find("Formation2")
    if self._battleConfig and self._battleConfig.showMode == BattleViewMode.Formation then
        ShowObject(teamRoot2.gameObject, false)
    else
        ShowObject(teamRoot2.gameObject, true)
    end

    if self._isBattleMode then
        if self._battleFormation1 and IsValid(teamRoot1) then
            self._localCnt = self._localCnt + BattlePosCount
        end
        if self._battleFormation2 and IsValid(teamRoot2) then
            self._localCnt = self._localCnt + BattlePosCount
        end
        self:LoadBattleTeam(BattleTeamSide.teamA, formationData1, self._battleFormation1)
        self:LoadBattleTeam(BattleTeamSide.teamB, formationData2, self._battleFormation2)
    else
        if self._formationObj1 and IsValid(teamRoot1) then
            self._localCnt = self._localCnt + BattlePosCount
        end
        if self._formationObj2 and IsValid(teamRoot2) then
            self._localCnt = self._localCnt + BattlePosCount
        end
        self:CheckIsSwapHero(self._formationObj1,self._teamA)
        self:LoadFormationTeam(BattleTeamSide.teamA, formationData1, self._formationObj1)
        self:LoadFormationTeam(BattleTeamSide.teamB, formationData2, self._formationObj2)
    end
end

--- 检查是否是相同的英雄换位
---@param formationObj LxFormationObj
function LBattleViewUnitMgr:CheckIsSwapHero(formationObj,team)
    if not formationObj then return false end

    local recordNewNum = 0
    local recordNewPosMap = {}
    for k,v in pairs(formationObj.positions) do
        recordNewNum = recordNewNum + 1
        recordNewPosMap[v.id] = v.index
    end

    local index,id
    for k,v in pairs(self._unitMap) do
        index = v.index
        if recordNewPosMap[k] ~= index then
            local unitView = team[index]
            if unitView then
                id = unitView.id
                unitView:Dispose()
                team[index] = nil
                self._unitMap[id] = nil
            end
        end
    end
end

---@param teamIdx number
---@param formationData V_ViewFace_FormationData[]
---@param formation LxFormationObj
function LBattleViewUnitMgr:LoadFormationTeam(teamIdx, formationData, formation)
    if not formation then
        for i = 1, BattlePosCount do
            local pointData = formationData[i]
            local bLock = ModuleCenter.Battle:IsPosLock(i, 0)
            local bShowNum = not bLock
            ShowObject(pointData.standObj, not self.isSkillEditor)
            ShowObject(pointData.lockObj, bLock)
            ShowObject(pointData.qualityObj, not bLock)
            if not bLock then
                for k,v in pairs(pointData.qualityObjList) do
                    ShowObject(v, k == 1)
                end
            end
            ShowObject(pointData.selObj, false)
            --bShowNum = false
            ShowObject(pointData.numObj, bShowNum)
            if bShowNum then
                local textMesh = pointData.numTrans:GetComponent(typeofCTextMesh)
                textMesh.text = tostring(ModuleCenter.Battle:ConvertGridPosToIndex(0, i))
            end
            local battleStateObj = pointData.battleStateObj
            if battleStateObj then
                ShowObject(battleStateObj, not bLock)
            end
        end
        return
    end

    local formationRefId = formation.formationRefId

    for i = 1, BattlePosCount do
        local unitObj = formation.positions[i]
        local pointData = formationData[i]
        local node = pointData.pointTrans

        local bLock =  ModuleCenter.Battle:IsPosLock(i,formationRefId)
        local bShowNum = not bLock and  (unitObj == nil)

        ShowObject(pointData.standObj, not self.isSkillEditor)
        ShowObject(pointData.lockObj, bLock)
        ShowObject(pointData.qualityObj, not bLock)
        if not bLock then
            for k,v in pairs(pointData.qualityObjList) do
                ShowObject(v, k == 1)
            end
        end
        ShowObject(pointData.selObj, false)

        --bShowNum = false
        ShowObject(pointData.numObj, bShowNum)
        if bShowNum then
            local textMesh = pointData.numTrans:GetComponent(typeofCTextMesh)
            textMesh.text = tostring(ModuleCenter.Battle:ConvertGridPosToIndex(formationRefId, i))
        end

        local battleStateObj = pointData.battleStateObj
        if battleStateObj then
            ShowObject(battleStateObj, not bLock)
        end

        self:AddUnitView(teamIdx, node, node, i, unitObj, Vector3.zero, nil,true)
    end
end
---@param teamIdx number
---@param formationData V_ViewFace_FormationData[]
---@param formation LFightFormationData
function LBattleViewUnitMgr:LoadBattleTeam(teamIdx, formationData, formation)
    if formationData == nil then
        return
    end
    if not formation then
        for i = 1, BattlePosCount do
            local node = formationData[i]
            local stand = node.standTrans
            if stand then
                ShowObject(stand.gameObject, false)
                ShowAllChild(stand.gameObject, false)
            end
        end
        return
    end

    ---@type table<number,LBattleUnitGridData>
    local positions = {}
    for i, v in pairs(formation.grids) do
        if v.unitType == BattleUnitType.Monster then
            local monsterAttrRef = GameTable.MonsterAttrRef[v.refId]
            if monsterAttrRef then
                v.skinRefId = monsterAttrRef.effectId
            end
        end
        positions[v.index] = v
    end

    local formationGrid = teamIdx == BattleTeamSide.teamA and self._viewFace._mapFormation1Grid or self._viewFace._mapFormation2Grid
    local trans = self._formationRoot.transform
    local teamRoot = teamIdx == BattleTeamSide.teamA and trans:Find("Formation1Root") or trans:Find("Formation2Root")

    for i = 1, BattlePosCount do
        local node = formationData[i]
        --- 先把站位节点删掉
        local stand = node.standTrans
        if stand then
            ShowObject(stand.gameObject, false)
            ShowAllChild(stand.gameObject, false)
        end
        local standRoot = node.pointTrans
        local unitObj = positions[i]
        local gridPos = formationGrid[i]
        local unitData = unitObj and self._logicMgr:GetLogicUnit(unitObj.id)
        local unitView = self:AddUnitView(teamIdx, teamRoot, standRoot, i, unitObj, gridPos, unitData, false)
    end
end


---@param unitData LBattleLogicUnit
---@param unitObj LBattleUnitGridData
function LBattleViewUnitMgr:AddSummonView(unitObj, unitData, loadCallback)
    local teamIdx = unitObj.teamType
    local trans = self._formationRoot.transform
    local grids = self._viewFace._mapFormation1Grid
    local teamRoot = trans:Find("Formation1Root")
    if teamIdx == BattleTeamSide.teamB then
        grids = self._viewFace._mapFormation2Grid
        teamRoot = trans:Find("Formation2Root")
    end

    local posIdx = unitObj.index
    local node = teamRoot
    local pos = grids[posIdx]
    local unitView = self._unitMap[unitObj.id]
    if unitView then
        unitView:SetSummon(true)
        unitView:SetViewMgr(self._viewMgr)
        unitView:SetGridPos(pos)
        unitView:SetUnitView(node, teamIdx, unitObj)
        unitView:SetUnitData(unitData)
        if loadCallback then
            loadCallback(unitView)
        end
    else
        unitView = require("LApp.gameplay.videobattle.view.LBattleViewUnit"):new()
        self._unitMap[unitObj.id] = unitView
        if teamIdx == BattleTeamSide.teamA then
            self._teamA[posIdx] = unitView
        else
            self._teamB[posIdx] = unitView
        end
        unitView:SetSummon(true)
        unitView:SetViewMgr(self._viewMgr)
        unitView:SetGridPos(pos)
        unitView:SetLoadCallback(loadCallback)
        unitView:SetUnitView(node, teamIdx, unitObj)
        unitView:SetUnitData(unitData)
        unitView:LoadUnitView()
    end
    return unitView
end

---@param unitObj LxUnitPosObj
function LBattleViewUnitMgr:AddUnitView(teamIdx, node, standRoot, posIdx, unitObj, gridPos, logicUnit, bFormationMode)
    local team = self:GetTeam(teamIdx)
    if unitObj and unitObj.id then
        self._unitMap[unitObj.id] = nil
    end

    ---@type LBattleViewUnit
    local unitView = team[posIdx]
    if unitView then
        self._unitMap[unitView.id] = nil
        -- 位置没有数据，删除原来的View
        if not unitObj then
            team[posIdx] = nil
            unitView:Dispose()
            self:OnLoadUnitView()
            return nil
        end

        -- 如果站位模型不对，先删掉
        if self.isSkillEditor then
            local modelName = unitObj.model
            if (unitView.modelName ~= modelName) then
                unitView:Dispose()
                unitView = nil
                team[posIdx] = nil
            end
        else
            local heroRefId = tonumber(unitObj.heroRefId or unitObj.refId)
            local skinRefId = tonumber(unitObj.skinRefId)
            if (unitView.heroRefId ~= heroRefId or unitView.heroRefId == 0) and (unitView.skinRefId ~= skinRefId or unitView.skinRefId == 0) then
                unitView:Dispose()
                unitView = nil
                team[posIdx] = nil
            end
        end

    end

    if IsNull(node)  or not unitObj then
        self:OnLoadUnitView()
        return nil
    end

    if not unitView then
        unitView = require("LApp.gameplay.videobattle.view.obj.LBattleViewUnit"):new()
        if unitObj.id then
            self._unitMap[unitObj.id] = unitView
        end
        team[posIdx] = unitView
        unitView:SetFormationMode(bFormationMode)
        unitView:Initialize()
        unitView:SetGridPos(gridPos)
        unitView:SetStandRoot(standRoot)
        unitView:SetEditorMode(self.isSkillEditor)
        unitView:SetViewMgr(self._viewMgr)
        unitView:SetLoadCallback(function(obj)
            --obj:LoadModelData(function()
                self:OnLoadUnitView(obj)
            --end)
        end)
        unitView:SetUnitView(node, teamIdx, unitObj)
        if not bFormationMode then
            unitView:SetUnitData(logicUnit)
        end
        unitView:LoadUnitView()
    else
        if unitObj.id then
            self._unitMap[unitObj.id] = unitView
        end
        team[posIdx] = unitView
        unitView:SetFormationMode(bFormationMode)
        unitView:SetEditorMode(self.isSkillEditor)
        unitView:SetUnitView(node, teamIdx, unitObj)
        unitView:SetGridPos(gridPos)
        unitView:SetStandRoot(standRoot)
        if not bFormationMode then
            unitView:SetUnitData(logicUnit)
        end
        unitView:Reset()
        unitView:ResetUnitRoot()
        if self.isSkillEditor then
            unitView:LoadModelData(function()
                self:OnLoadUnitView(unitView)
            end)
        else
            self:OnLoadUnitView(unitView)
        end

    end
    unitView:ShowStandQuality(bFormationMode and not self.isSkillEditor)

    if not self._isBattleMode and not self.isSkillEditor then
        unitView:SetModelScale(BattleUnitScale)
    end

    return unitView
end
---@param unitView LBattleViewUnit
function LBattleViewUnitMgr:OnLoadUnitView(unitView)
    local spineDp = unitView and unitView:GetModelDp()
    if spineDp and spineDp:IsDpValid() then
        --local objectClicker = spineDp:GetObjectClicker()
        --if objectClicker then
        --    objectClicker.onClick = function()
        --        print("objectClicker.onClick")
        --    end
        --    objectClicker.onClickBegin = function()
        --        print("objectClicker.onClickBegin")
        --    end
        --    objectClicker.onClickEnd = function()
        --        print("objectClicker.onClickEnd")
        --    end
        --    objectClicker.onDrag = function()
        --        print("objectClicker.onDrag")
        --    end
        --end
    end
    self._localIdx = self._localIdx + 1
    if self._localIdx == self._localCnt  then
        if self._localCallback then
            self._localCallback()
        end
    end
    if self.isSkillEditor then
        if unitView and unitView.index == 2 and unitView.teamIdx == BattleTeamSide.teamA then
            FireEvent(EventNames.BATTLE_MODEL_LOAD, {modelDp = unitView:GetModelDp()})
        end
    end

end

function LBattleViewUnitMgr:GetTeamUnit(teamSide, pos)
    local team = self:GetTeam(teamSide)
    if team then
        return team[pos]
    else
        return nil
    end
end

function LBattleViewUnitMgr:GetFrontUnit(teamSide, posIdx)
    if posIdx > 3 then
        posIdx = posIdx - 3
    end
    return self:GetTeamUnit(teamSide, posIdx)
end

function LBattleViewUnitMgr:GetTeam(teamSide)
    if teamSide == BattleTeamSide.teamA then
        return self._teamA
    else
        return self._teamB
    end
end

function LBattleViewUnitMgr:ReadyBattle()
    self:SetEmpty()
    for i, v in pairs(self._unitMap) do
        v:ReadyBattle()
    end
end


function LBattleViewUnitMgr:RemoveUnitView(id)
    local obj = self._unitMap[id]
    self._unitMap[id] = nil
    if not obj then
        return
    end
    obj:Dispose()

    local side = obj:GetTeamIdx()
    if side == BattleTeamSide.teamA then
        table.removebyvalue(self._teamA,obj)
    else
        table.removebyvalue(self._teamB,obj)
    end
    return true
end

-----------------------------------------------------------------
function LBattleViewUnitMgr:OnUpdate(time, deltaTime)
    for k,v in pairs(self._unitMap) do
        v:OnUpdate(time, deltaTime)
    end
end


---获取同一方有效队伍列表
---@return LBattleViewUnit[]
function LBattleViewUnitMgr:GetTeamNormalListBySide(side)
    local list = nil
    if side == BattleTeamSide.teamA then
        list = self._teamA
    else
        list = self._teamB
    end

    local temp= {}
    for k,v in pairs(list) do
        if v:GetObjectType() == LFightConst.OBJ_NORMAL then
            table.insert(temp,v)
        end
    end

    return temp
end


---根据唯一id获取对象
---@return LBattleViewUnit
function LBattleViewUnitMgr:GetUnitView(id)
    return self._unitMap[id]
end

-----------------------------------------------------------------
function LBattleViewUnitMgr:ClearAllObject()
    local objList = self._unitMap
    if objList  then
        for k,v in pairs(objList) do
            v:Dispose()
        end
    end
    self._unitMap = {}
    self._teamA = {}
    self._teamB = {}
end

function LBattleViewUnitMgr:IsAllDeadTweenEnd()
    local objList = self._unitMap
    if(objList) then
        for k,v in pairs(objList) do
            local objData  = v:GetHeroData()
            if objData:GetBattleObjType() == LFightConst.OBJ_NORMAL then
                local isDead = v:IsDead()
                local isDeadTweenEnd = v:IsDeadTweenEnd()
                if isDead and not isDeadTweenEnd then
                    return false
                end
            end
        end
    end

    return true
end

function LBattleViewUnitMgr:UpdateHeroMap()
    self._heroMapByIndex = {
        [BattleTeamSide.teamA] = {},
        [BattleTeamSide.teamB] = {},
    }

    for k,v in pairs(self._unitMap) do
        if v:IsOnGridObj() then
            local side = v:GetTeamType()
            local index = v:GetIndex()
            self._heroMapByIndex[side][index] = v
        end
    end
end

---@param effect LBattleBaseEffectData
function LBattleViewUnitMgr:SwapHero(side,effect,duration)
    local eId = effect.eId
    for k,obj in pairs(self._unitMap) do
        if obj:IsOnGridObj() and eId == obj:GetId() then
            obj:ChangeIndex(effect.positionEffect,duration)
        end
    end
end


function LBattleViewUnitMgr:DestroyBySide(side)
    local teamList = nil
    if side == BattleTeamSide.teamA then
        teamList = self._teamA
        self._teamA = {}
    else
        teamList = self._teamB
        self._teamB = {}
    end

    local cnt = #teamList
    for k=cnt,1,-1 do
        local obj = teamList[k]
        local id = obj:GetId()
        self._unitMap[id] = nil
    end

    for k,v in ipairs(teamList) do
        v:Destroy()
    end
end



-----------------------------------------------------------------
function LBattleViewUnitMgr:Dispose()
    if self._isDisposed then
        return
    end
    self:ClearAllObject()
    table.dispose(self)
    self._isDisposed = true
end
-----------------------------------------------------------------

return LBattleViewUnitMgr